167→    private fun PostPrepublishingBottomSheetBinding.setupMinimumHeightForFragmentContainer() {
168→        val isPage = checkNotNull(arguments?.getBoolean(IS_PAGE)) {
169→            "arguments can't be null."
170→        }
171→
172→        if (isPage) {
173→            prepublishingContentFragment.minimumHeight =
174→                resources.getDimensionPixelSize(R.dimen.prepublishing_fragment_container_min_height_for_page)
175→        } else {
176→            prepublishingContentFragment.minimumHeight =
177→                resources.getDimensionPixelSize(R.dimen.prepublishing_fragment_container_min_height)
178→        }
179→    }
180→
181→    private fun initViewModel(savedInstanceState: Bundle?) {
182→        viewModel = ViewModelProvider(this, viewModelFactory)[PrepublishingViewModel::class.java]
183→
184→        viewModel.navigationTarget.observeEvent(this) { navigationState ->
185→            navigateToScreen(navigationState)
186→        }
187→
188→        viewModel.dismissBottomSheet.observeEvent(this) {
189→            dismiss()
190→        }
191→
192→        viewModel.triggerOnSubmitButtonClickedListener.observeEvent(this) { publishPost ->
193→            prepublishingBottomSheetListener?.onSubmitButtonClicked(publishPost)
194→        }
195→
196→        viewModel.dismissKeyboard.observeEvent(this) {
197→            ActivityUtils.hideKeyboardForced(view)
198→        }
199→
200→        viewModel.navigateToSharingSettings.observeEvent(this) { site ->
201→            context?.let { ActivityLauncher.viewBlogSharing(it, site) }
202→        }
203→
204→        val prepublishingScreenState = savedInstanceState?.getParcelableCompat<PrepublishingScreen>(
205→            KEY_SCREEN_STATE
206→        )
207→        val site = requireNotNull(arguments?.getSerializableCompat<SiteModel>(SITE))
208→        viewModel.start(site, prepublishingScreenState)
209→    }
210→
211→    private fun navigateToScreen(navigationTarget: PrepublishingNavigationTarget) {
212→        val (fragment, tag) = when (navigationTarget.targetScreen) {
213→            HOME -> {
214→                val isStoryPost = checkNotNull(arguments?.getBoolean(IS_STORY_POST)) {
215→                    "arguments can't be null."
216→                }
217→                Pair(
218→                    PrepublishingHomeFragment.newInstance(isStoryPost),
219→                    PrepublishingHomeFragment.TAG
220→                )
221→            }
222→
223→            PUBLISH -> Pair(
224→                PrepublishingPublishSettingsFragment.newInstance(),
225→                PrepublishingPublishSettingsFragment.TAG
226→            )
227→
228→            TAGS -> {
229→                val isStoryPost = checkNotNull(arguments?.getBoolean(IS_STORY_POST)) {
230→                    "arguments can't be null."
231→                }
232→                Pair(
233→                    PrepublishingTagsFragment.newInstance(navigationTarget.site, isStoryPost),
234→                    PrepublishingTagsFragment.TAG
235→                )
236→            }
237→
238→            CATEGORIES -> {
239→                val isStoryPost = checkNotNull(arguments?.getBoolean(IS_STORY_POST)) {
240→                    "arguments can't be null."
241→                }
242→                Pair(
243→                    PrepublishingCategoriesFragment.newInstance(
244→                        navigationTarget.site,
245→                        isStoryPost,
246→                        navigationTarget.bundle
247→                    ),
248→                    PrepublishingCategoriesFragment.TAG
249→                )
250→            }
251→
252→            ADD_CATEGORY -> {
253→                val isStoryPost = checkNotNull(arguments?.getBoolean(IS_STORY_POST)) {
254→                    "arguments can't be null."
255→                }
256→                Pair(
257→                    PrepublishingAddCategoryFragment.newInstance(
258→                        navigationTarget.site,
259→                        isStoryPost,
260→                        navigationTarget.bundle
261→                    ),
262→                    PrepublishingAddCategoryFragment.TAG
263→                )
264→            }
265→
266→            SOCIAL -> {
267→                Pair(
268→                    PrepublishingSocialFragment.newInstance(),
269→                    PrepublishingSocialFragment.TAG
270→                )
271→            }
272→        }
273→
274→        fadeInFragment(fragment, tag)
275→    }
276→
277→    private fun fadeInFragment(fragment: Fragment, tag: String) {
278→        childFragmentManager.let { fragmentManager ->
279→            val fragmentTransaction = fragmentManager.beginTransaction()
280→            fragmentManager.findFragmentById(R.id.prepublishing_content_fragment)?.run {
281→                fragmentTransaction.addToBackStack(null).setCustomAnimations(
282→                    R.anim.prepublishing_fragment_fade_in,
283→                    R.anim.prepublishing_fragment_fade_out,
284→                    R.anim.prepublishing_fragment_fade_in,
285→                    R.anim.prepublishing_fragment_fade_out
286→                )
287→            }
288→            fragmentTransaction.replace(R.id.prepublishing_content_fragment, fragment, tag)
289→            fragmentTransaction.commit()
290→        }
291→    }
292→
293→    override fun onSaveInstanceState(outState: Bundle) {
294→        super.onSaveInstanceState(outState)
295→        viewModel.writeToBundle(outState)
296→    }
297→
298→    override fun onBackClicked(bundle: Bundle?) {
299→        viewModel.onBackClicked(bundle)
300→    }
301→
302→    override fun onActionClicked(actionType: ActionType, bundle: Bundle?) {
303→        viewModel.onActionClicked(actionType, bundle)
304→    }
305→
306→    override fun onSubmitButtonClicked(publishPost: PublishPost) {
307→        viewModel.onSubmitButtonClicked(publishPost)
308→    }
309→
310→    override fun getEditorJetpackSocialViewModel(): EditorJetpackSocialViewModel {
311→        jetpackSocialViewModel?.let {
312→            return it
313→        } ?: run {
314→            val viewModel = ViewModelProvider(
315→                requireActivity(), // try using the activity-scoped ViewModel, but only if it's started
316→                viewModelFactory
317→            )[EditorJetpackSocialViewModel::class.java].takeIf {
318→                it.isStarted
319→            } ?: run {
320→                ViewModelProvider(
321→                    this, // if not, let's use our own scope to create the ViewModel and start it
322→                    viewModelFactory
323→                )[EditorJetpackSocialViewModel::class.java].also {
324→                    val hook = getEditorHook()
325→                    it.start(hook.site, hook.editPostRepository)
326→                    // let's also handle the action events
327→                    it.actionEvents.observe(viewLifecycleOwner) { actionEvent ->
328→                        when (actionEvent) {
329→                            is OpenEditShareMessage -> {
330→                                val intent = createIntent(
331→                                    requireActivity(),
332→                                    actionEvent.shareMessage
333→                                )
334→                                editShareMessageActivityResultLauncher.launch(intent)
335→                            }
336→
337→                            is OpenSocialConnectionsList -> {
338→                                ActivityLauncher.viewBlogSharing(requireActivity(), actionEvent.siteModel)
339→                            }
340→
341→                            is OpenSubscribeJetpackSocial -> {
342→                                WPWebViewActivity.openUrlByUsingGlobalWPCOMCredentials(
343→                                    requireActivity(),
344→                                    actionEvent.url
345→                                )
346→                            }
347→                        }
348→                    }
349→                }
350→            }
351→
352→            return viewModel.also { jetpackSocialViewModel = it }
353→        }
354→    }
355→
356→    @Suppress("TooGenericExceptionThrown")
357→    private fun getEditorHook(): EditPostActivityHook {
358→        val activity = activity
359→        return if (activity is EditPostActivityHook) {
360→            activity
361→        } else {
362→            throw RuntimeException("$activity must implement EditPostActivityHook")
363→        }
364→    }
365→
366→    companion object {
367→        const val TAG = "prepublishing_bottom_sheet_fragment_tag"
368→        const val SITE = "prepublishing_bottom_sheet_site_model"
369→        const val IS_PAGE = "prepublishing_bottom_sheet_is_page"
370→        const val IS_STORY_POST = "prepublishing_bottom_sheet_is_story_post"
371→
372→        @JvmStatic
373→        fun newInstance(site: SiteModel, isPage: Boolean, isStoryPost: Boolean) =
374→            PrepublishingBottomSheetFragment().apply {
375→                arguments = Bundle().apply {
376→                    putSerializable(SITE, site)
377→                    putBoolean(IS_PAGE, isPage)
378→                    putBoolean(IS_STORY_POST, isStoryPost)
379→                }
380→            }
381→    }
382→}
