@ExperimentalCoroutinesApi
class PrepublishingHomeViewModelCategoryTest : BaseUnitTest() {
    private lateinit var viewModel: PrepublishingHomeViewModel

    @Mock
    lateinit var postSettingsUtils: PostSettingsUtils

    @Mock
    lateinit var editPostRepository: EditPostRepository

    @Mock
    lateinit var getPostTagsUseCase: GetPostTagsUseCase

    @Mock
    lateinit var getButtonUiStateUseCase: GetButtonUiStateUseCase

    @Mock
    lateinit var storyRepositoryWrapper: StoryRepositoryWrapper

    @Mock
    lateinit var updateStoryTitleUseCase: UpdateStoryPostTitleUseCase

    @Mock
    lateinit var getCategoriesUseCase: GetCategoriesUseCase

    @Mock
    lateinit var site: SiteModel

    @Before
    fun setUp() {
        viewModel = PrepublishingHomeViewModel(
            getPostTagsUseCase,
            postSettingsUtils,
            getButtonUiStateUseCase,
            mock(),
            storyRepositoryWrapper,
            updateStoryTitleUseCase,
            getCategoriesUseCase,
            testDispatcher()
        )
        whenever(
            getButtonUiStateUseCase.getUiState(
                any(),
                any(),
                any()
            )
        ).thenAnswer {
            PrepublishingHomeItemUiState.PublishButtonUiState(it.arguments[2] as (PublishPost) -> Unit)
        }
        whenever(editPostRepository.getEditablePost()).thenReturn(PostModel())
        whenever(editPostRepository.title).thenReturn("")
        whenever(editPostRepository.status).thenReturn(PostStatus.PUBLISHED)
        whenever(postSettingsUtils.getPublishDateLabel(any())).thenReturn("")
        whenever(site.name).thenReturn("")
        whenever(storyRepositoryWrapper.getCurrentStoryThumbnailUrl()).thenReturn("")
        whenever(getCategoriesUseCase.getPostCategoriesString(any(), any())).thenReturn("Test Category")

        viewModel.uiState.observeForever(mock())
    }

    @Test
    fun `verify that categories action is NOT propagated to home ui state for pages`() {
        // arrange - page should not show categories
        whenever(editPostRepository.isPage).thenReturn(true)

        // act
        viewModel.start(editPostRepository, site, false)

        // assert
        val categoriesAction = getHomeUiState(PrepublishingScreenNavigation.Categories)
        assertThat(categoriesAction).isNull()
        // For pages, we should only have 2 HomeUiState items (Publish) since tags and categories should not be shown
        assertThat(viewModel.uiState.value?.filterIsInstance(HomeUiState::class.java)?.size).isEqualTo(1)
    }

    @Test
    fun `verify that categories action IS propagated to home ui state for posts`() {
        // arrange - posts should show categories
        whenever(editPostRepository.isPage).thenReturn(false)

        // act
        viewModel.start(editPostRepository, site, false)

        // assert
        val categoriesAction = getHomeUiState(PrepublishingScreenNavigation.Categories)
        assertThat(categoriesAction).isNotNull()
        // For posts, we should have 3 HomeUiState items (Publish, Tags, Categories)
        assertThat(viewModel.uiState.value?.filterIsInstance(HomeUiState::class.java)?.size).isEqualTo(3)
    }

    private fun getHomeUiState(actionType: PrepublishingScreenNavigation): HomeUiState? {
        val actions = viewModel.uiState.value
            ?.filterIsInstance(HomeUiState::class.java)
        return actions?.find { it.navigationAction == actionType }
    }
